const categoryList = document.getElementById('category-list');
const addCategoryButton = document.querySelector('.add-category-button');

function renderCategories() {
    categoryList.innerHTML = '';
    budgetCategories.forEach(category => {
        const card = document.createElement('div');
        card.className = `category-card ${getBalanceStatus(category)}`;
        card.innerHTML = `
            <h3>${category.name}</h3>
            <p>Balance: $${category.balance}</p>
            <p>Limit: $${category.limit}</p>
            <button class="edit-button">Edit</button>
        `;
        categoryList.appendChild(card);
    });
}

function getBalanceStatus(category) {
    if (category.balance <= category.limit) {
        return 'green';
    } else if (category.balance <= category.limit * 1.1) {
        return 'yellow';
    } else {
        return 'red';
    }
}

function showForm(category) {
    const form = document.createElement('div');
    form.className = 'form';
    form.innerHTML = `
        <h3>Edit ${category.name}</h3>
        <input type="number" id="new-balance" value="${category.balance}">
        <button class="save-button">Save</button>
    `;
    categoryList.appendChild(form);

    const saveButton = form.querySelector('.save-button');
    saveButton.addEventListener('click', () => {
        const newBalance = parseFloat(document.getElementById('new-balance').value);
        if (newBalance > category.limit) {
            alert('Balance cannot exceed limit');
        } else {
            category.balance = newBalance;
            renderCategories();
        }
    });
}

addCategoryButton.addEventListener('click', () => {
    const form = document.createElement('div');
    form.className = 'form';
    form.innerHTML = `
        <h3>Add Category</h3>
        <input type="text" id="new-category-name" placeholder="Category Name">
        <input type="number" id="new-category-limit" placeholder="Monthly Limit">
        <button class="add-button">Add</button>
    `;
    categoryList.appendChild(form);

    const addButton = form.querySelector('.add-button');
    addButton.addEventListener('click', () => {
        const name = document.getElementById('new-category-name').value;
        const limit = parseFloat(document.getElementById('new-category-limit').value);
        budgetCategories.push({ name, balance: 0, limit });
        renderCategories();
    });
});

categoryList.addEventListener('click', (event) => {
    if (event.target.classList.contains('edit-button')) {
        const category = budgetCategories.find(cat => categoryList.querySelector(`.category-card h3`).textContent === event.target.parentNode.querySelector('h3').textContent);
        showForm(category);
    }
});

renderCategories();

